            revert InvalidAmount();
        }

        uint256 available = token.balanceOf(address(this));

        if (available < amount) {
            revert InsufficientVaultBalance(available, amount);
        }

        token.safeTransfer(recipient, amount);

        emit InterestPaid(_msgSender(), recipient, amount);
    }

